from bisect import bisect_right
class Solution:
    def kIncreasing(self, arr: List[int], k: int) -> int:
        n = len(arr)
        res = 0
        for r in range(k):
            seq = arr[r:n:k]
            tails = []
            for val in seq:
                idx = bisect_right(tails, val)
                if idx == len(tails):
                    tails.append(val)
                else:
                    tails[idx] = val
            res += len(seq) - len(tails)
        return res
